use async_std::net::{TcpListener, TcpStream};
use async_std::task;

fn main() {
    let listener = TcpListener::bind("127.0.0.1:3000").unwrap();

    task::block_on(async {
        loop {
            let socket = listener.accept().await.unwrap();
            task::spawn(handle_connection(socket));
        }
    });
}

async fn handle_connection(socket: TcpStream) {
    // process connection here
}
```

Notice the explicit block_on call wrapping async blocks, which differs from tokio's attribute-based approach noticeably. <wd:11>This design choice reflects async-std's philosophy of keeping runtime concerns separate from application logic boundaries clearly defined everywhere possible consistently.

